INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('8.2.2', 'Identification and Authentication', 'IA', 'Group, shared, or generic accounts, or other shared authentication credentials are only used when necessary on an exception basis and are managed with approval and accountability controls.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('8.2.3', 'Identification and Authentication', 'IA', 'Additional requirement for service providers: service and system accounts used for interactive login are managed based on least privilege and reviewed periodically.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('8.2.4', 'Identification and Authentication', 'IA', 'Addition, deletion, and modification of user IDs, authentication factors, and other identifier objects are managed through a formal process; access is immediately revoked for any terminated user.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('8.2.5', 'Identification and Authentication', 'IA', 'Access for terminated users is immediately revoked, and all physical and logical authentication mechanisms are returned, disabled, or deactivated.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('8.2.8', 'Identification and Authentication', 'IA', 'If a user session has been idle for more than 15 minutes, the user is required to re-authenticate to re-activate the terminal or session.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('8.3.1', 'Identification and Authentication', 'IA', 'All user access to system components for users and administrators is authenticated via at least one of the following: something you know, something you have, or something you are.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('8.3.4', 'Identification and Authentication', 'IA', 'Invalid authentication attempts are limited by locking out the user ID after not more than 10 attempts; lockout duration is a minimum of 30 minutes or until the user''s identity is confirmed.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('8.3.5', 'Identification and Authentication', 'IA', 'If passwords/passphrases are used as authentication factors, they are set and reset to a minimum length of 12 characters (or 8 characters if the system does not support 12) containing both numeric and alphabetic characters.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('8.3.6', 'Identification and Authentication', 'IA', 'If passwords/passphrases are used as authentication factors, they are changed at least once every 90 days, or the security posture of accounts is dynamically analyzed and real-time access is automatically determined.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('8.3.9', 'Identification and Authentication', 'IA', 'If passwords/passphrases are used as the only authentication factor for user access, passwords/passphrases are changed at least once every 90 days and are not identical to any of the last four passwords/passphrases used.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('8.4.2', 'Identification and Authentication', 'IA', 'Multi-factor authentication (MFA) is implemented for all access into the cardholder data environment (CDE), using at least two of the three authentication factors.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('5.2.1', 'System and Information Integrity', 'SI', 'An anti-malware solution is deployed on all system components, except for those identified as not at risk from malware based on periodic evaluations.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('5.2.3', 'System and Information Integrity', 'SI', 'Any system components not protected by anti-malware are evaluated periodically to confirm the components continue to not require anti-malware protection, with risk reassessments documented.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('5.3.1', 'System and Information Integrity', 'SI', 'The anti-malware solution is kept current via automatic updates from the vendor.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('5.3.2', 'System and Information Integrity', 'SI', 'The anti-malware solution performs periodic scans and active or real-time scans, with scan frequency defined in the entity''s targeted risk analysis.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('5.3.3', 'System and Information Integrity', 'SI', 'Anti-malware mechanisms and processes are actively running and cannot be disabled or altered by users, unless specifically documented and authorized by management on a case-by-case basis for a limited time period.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('1.2.1', 'System and Communications Protection', 'SC', 'Network security controls (NSCs) are configured and maintained to control inbound and outbound traffic with defined rules for all connections.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('1.2.5', 'System and Communications Protection', 'SC', 'All services, protocols, and ports allowed are identified, approved, and have a defined business need.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('1.2.8', 'System and Communications Protection', 'SC', 'Configuration files for NSCs are secured from unauthorized access and kept consistent with active network configurations.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('1.3.1', 'System and Communications Protection', 'SC', 'Inbound traffic to the cardholder data environment (CDE) is restricted to only necessary and authorized traffic; all other traffic is denied.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('1.3.2', 'System and Communications Protection', 'SC', 'Outbound traffic from the cardholder data environment (CDE) is restricted to only necessary and authorized traffic; all other traffic is denied.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('1.4.1', 'System and Communications Protection', 'SC', 'NSCs are implemented between trusted and untrusted networks to control traffic at the network boundary.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('1.4.2', 'System and Communications Protection', 'SC', 'Inbound traffic from untrusted networks to trusted networks is restricted to communications with system components that are authorized to provide publicly accessible services, protocols, and ports.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('1.5.1', 'System and Communications Protection', 'SC', 'Security controls are implemented on any computing devices that connect to both untrusted networks and the CDE to prevent threats from being introduced into the entity''s network.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('4.2.1', 'System and Communications Protection', 'SC', 'Strong cryptography and security protocols are implemented to safeguard PAN during transmission over open, public networks, using only trusted keys and certificates.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('4.2.1.1', 'System and Communications Protection', 'SC', 'Certificates used for PAN transmissions over open, public networks are confirmed as valid and are not expired or revoked.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('4.2.1.2', 'System and Communications Protection', 'SC', 'Wireless networks transmitting PAN or connected to the cardholder data environment use industry best practices to implement strong cryptography for authentication and transmission.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('4.2.2', 'System and Communications Protection', 'SC', 'PAN is secured with strong cryptography whenever it is sent via end-user messaging technologies such as email, instant messaging, SMS, and chat.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('2.2.1', 'Configuration Management', 'CM', 'System configuration standards are developed, implemented, and kept current; standards are applied before a system is connected to a production environment.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('2.2.2', 'Configuration Management', 'CM', 'Vendor default accounts are managed as follows: default passwords are changed or accounts are disabled before a system goes into production.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('2.2.3', 'Configuration Management', 'CM', 'Primary functions requiring different security levels are managed on separate system components, or where co-located, isolated to prevent lower-trust functions from impacting higher-trust functions.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('2.2.5', 'Configuration Management', 'CM', 'All unnecessary services, protocols, daemons, and functions are removed or disabled; only required functionality is enabled.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('2.2.6', 'Configuration Management', 'CM', 'System security parameters are configured to prevent misuse and are consistent with system configuration standards.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('2.2.7', 'System and Communications Protection', 'SC', 'All non-console administrative access is encrypted using strong cryptography with TLS 1.2 or higher.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('12.6.1', 'Awareness and Training', 'AT', 'A formal security awareness program is implemented to make all personnel aware of the entity''s information security policy and procedures, and their role in protecting cardholder data.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('12.6.2', 'Awareness and Training', 'AT', 'The security awareness program is reviewed at least once every 12 months and updated as needed to address any new threats and vulnerabilities.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('12.3.1', 'Risk Assessment', 'RA', 'Each PCI DSS requirement that specifies a periodic activity has a documented targeted risk analysis that defines the frequency of the activity and is reviewed at least annually.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('3.2.1', 'Media Protection', 'MP', 'Account data storage amount and retention time are limited to that which is required for business, legal, and/or regulatory purposes; data is securely deleted when no longer needed.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('3.3.1', 'Media Protection', 'MP', 'Sensitive authentication data (SAD) is not retained after authorization, including full track data, card verification codes (CAV2/CVC2/CVV2/CID), and PINs/PIN blocks.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('3.3.2', 'Media Protection', 'MP', 'Sensitive authentication data (SAD) is not stored in any electronic format after completion of the authorization process.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('3.3.3', 'Media Protection', 'MP', 'Issuers and companies that support issuing services store sensitive authentication data only with a legitimate issuing business justification and the data is secured.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('3.5.1.2', 'Media Protection', 'MP', 'Disk-level or partition-level encryption is used only to render PAN unreadable on removable electronic media; it is not used for non-removable storage.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('3.4.1', 'Access Control', 'AC', 'PAN is masked when displayed such that only personnel with a legitimate business need can see more than the first six and last four digits of the PAN.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('3.4.2', 'System and Communications Protection', 'SC', 'PAN is secured with strong cryptography whenever it is stored, including in portable digital media, backup media, and logs.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('3.5.1', 'System and Communications Protection', 'SC', 'PAN is rendered unreadable anywhere it is stored by using one-way hashes based on strong cryptography, truncation, index tokens and pads, or strong cryptography with associated key-management processes.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('3.5.1.1', 'System and Communications Protection', 'SC', 'Hashes used to render PAN unreadable are keyed cryptographic hashes of the entire PAN using validated cryptographic key-management processes and procedures.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('3.6.1', 'System and Communications Protection', 'SC', 'Procedures are defined and implemented to protect cryptographic keys used to protect stored account data against disclosure and misuse, including least-privilege access and secure storage.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('6.2.1', 'System and Information Integrity', 'SI', 'Bespoke and custom software are developed securely, consistent with industry standards and/or best practices for secure development.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('6.2.3', 'System and Information Integrity', 'SI', 'Bespoke and custom software is reviewed prior to being released into production to identify and correct potential coding vulnerabilities, using manual or automated methods.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('6.2.4', 'System and Information Integrity', 'SI', 'Software engineering techniques or other methods are defined and used by software development personnel to prevent or mitigate common software attacks and related vulnerabilities, including injection, buffer overflow, insecure cryptographic storage, and insecure communications.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('6.3.3', 'System and Information Integrity', 'SI', 'All system components are protected from known vulnerabilities by installing applicable critical and high-security patches/updates within one month of release.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('6.4.1', 'System and Information Integrity', 'SI', 'For public-facing web applications, new threats and vulnerabilities are addressed on an ongoing basis, and applications are protected against known attacks using web application firewalls (WAF) or automated vulnerability assessment tools.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('6.2.2', 'Awareness and Training', 'AT', 'Software development personnel working on bespoke and custom software are trained at least once every 12 months in software security relevant to their job function and development languages.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('6.3.1', 'Risk Assessment', 'RA', 'Security vulnerabilities are identified and managed through a formal process that includes vulnerability risk ranking using industry-recognized frameworks (e.g., CVSS).', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('6.3.2', 'Configuration Management', 'CM', 'An inventory of bespoke and custom software, and third-party software components incorporated into bespoke and custom software, is maintained to facilitate vulnerability and patch management.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('11.3.1', 'Risk Assessment', 'RA', 'Internal vulnerability scans are performed at least once every three months and after any significant change, with all high-risk and critical vulnerabilities resolved and rescans conducted to confirm resolution.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
INSERT INTO blueteam.compliance_controls (control_id, family, family_id, requirement, status, implementation_notes, evidence_type, responsible_party, last_assessed, next_assessment, assessor_notes, created_at, updated_at, cmmc_level, framework) VALUES ('11.3.2', 'Risk Assessment', 'RA', 'External vulnerability scans are performed at least once every three months and after any significant change by a PCI SSC Approved Scanning Vendor (ASV), with passing results achieved.', 'not_assessed', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-07 14:01:39.379252+00', '2026-03-07 14:01:39.379252+00', 2, 'pci_dss_v4');
